cache='/tmp/supply_cache'
raw_sales_df=pd.read_pickle(f'{cache}/raw_sales_df.pkl')
batch_df=pd.read_pickle(f'{cache}/batch_df.pkl')
sales_agg=pd.read_pickle(f'{cache}/sales_agg.pkl')
stores=[f'S_{i}' for i in range(1,11)]
weights=np.array([0.8]*3+[0.5]*4+[0.2]*7)

def build_count_df(p):
    sales=raw_sales_df[raw_sales_df['Product_ID']==p].reset_index().rename(columns={'index':'orig_idx'})
    batches=batch_df[batch_df['product']==p].sort_values(['day','store_seq','supplier_seq','producer'])
    intake=defaultdict(list)
    for r in batches.itertuples(index=False):
        intake[(r.store,r.day)].append([r.producer,int(r.qty),int(r.supplier_day),int(r.supplier_seq)])
    counts=defaultdict(int)
    for store in stores:
        queue=deque()
        store_sales=sales[sales['Store_ID']==store]
        for day in range(1,366):
            day_sales=store_sales[store_sales['Day']==day].sort_values('orig_idx')
            for r in day_sales.itertuples(index=False):
                need=int(r.Sold_Quantity)
                touched=set()
                while need>0:
                    producer, avail, *_ = queue[0]
                    take=min(need, avail)
                    need-=take; avail-=take; touched.add(producer)
                    if avail==0:
                        queue.popleft()
                    else:
                        queue[0][1]=avail
                for producer in touched:
                    counts[(day,store,producer)] += 1
            for batch in intake.get((store,day),[]):
                queue.append(batch.copy())
    return pd.DataFrame([{'day':d,'store':s,'producer':pr,'count':c} for (d,s,pr),c in counts.items()])

def fit(p, count_df, placebo=False):
    Y=sales_agg[sales_agg['product']==p].pivot(index='day', columns='store', values='reported_demand').reindex(index=range(1,366), columns=stores).fillna(0).values.astype(float)
    producers=sorted(count_df['producer'].unique(), key=lambda x:int(x.split('_')[1]))
    X=np.zeros((365,10,len(producers)), dtype=float)
    for j,prod in enumerate(producers):
        piv=count_df[count_df['producer']==prod].pivot(index='day', columns='store', values='count').reindex(index=range(1,366), columns=stores).fillna(0).values
        exp=np.zeros_like(piv)
        if placebo:
            for lag,w in enumerate(weights, start=1):
                exp[:-lag]+=w*piv[lag:]
        else:
            for lag,w in enumerate(weights, start=1):
                exp[lag:]+=w*piv[:-lag]
        X[:,:,j]=exp
    U,S,Vt=np.linalg.svd(Y, full_matrices=False)
    a=np.abs(Vt[0]); c=np.abs(U[:,0])*S[0]; lam=np.zeros(len(producers)); F=X.reshape(-1,len(producers))
    for _ in range(30):
        R=Y + np.tensordot(X, lam, axes=([2],[0]))
        for _ in range(15):
            c=np.maximum((R@a)/max(a@a,1e-9), 1e-9)
            a=np.maximum((R.T@c)/max(c@c,1e-9), 1e-9)
        B=np.outer(c,a)
        lam_new,_=nnls(F,(B-Y).reshape(-1))
        if np.max(np.abs(lam_new-lam))<1e-6:
            lam=lam_new; break
        lam=lam_new
    return pd.Series(lam,index=producers).sort_values(ascending=False)
